/*Funciones del motor*/
static void ADC1_PA4_Init_ByRegisters(void)
{
    RCC->AHB1ENR |= RCC_AHB1ENR_GPIOAEN;
    (void)RCC->AHB1ENR;

    GPIOA->MODER |= (3UL << (4U * 2U));
    GPIOA->PUPDR &= ~(3UL << (4U * 2U));

    RCC->APB2ENR |= RCC_APB2ENR_ADC1EN;
    (void)RCC->APB2ENR;

    /*
     * PCLK2 = 84 MHz
     * ADC clock = PCLK2 / 4 = 21 MHz
     */
    ADC->CCR &= ~(3UL << 16U);
    ADC->CCR |=  (1UL << 16U);

    /*
     * CR1 = 0:
     * - Resolución 12 bits
     * - Scan mode deshabilitado
     *
     * CR2 = 0:
     * - Conversión continua deshabilitada
     * - Alineación a la derecha
     * - Disparo por software
     */
    ADC1->CR1 = 0U;
    ADC1->CR2 = 0U;

    /*
     * Tiempo de muestreo del canal 4:
     * SMP4 = 100 -> 84 ciclos de ADC.
     */
    ADC1->SMPR2 &= ~(7UL << (4U * 3U));
    ADC1->SMPR2 |=  (4UL << (4U * 3U));

    /*
     * Secuencia regular de una sola conversión.
     */
    ADC1->SQR1 &= ~(0xFUL << 20U);

    /*
     * Primera conversión: canal 4.
     */
    ADC1->SQR3 &= ~(0x1FUL << 0U);
    ADC1->SQR3 |=  (4UL << 0U);

    ADC1->CR2 &= ~ADC_CR2_ALIGN;
    ADC1->CR2 &= ~ADC_CR2_CONT;
    ADC1->CR2 &= ~ADC_CR2_EXTEN;

    ADC1->CR2 |= ADC_CR2_ADON;

    HAL_Delay(1);
}


static uint32_t ADC1_ReadRaw(void)
{
    ADC1->SR &= ~ADC_SR_EOC;

    ADC1->CR2 |= ADC_CR2_SWSTART;

    while ((ADC1->SR & ADC_SR_EOC) == 0U)
    {
        /* Polling */
    }

    return (ADC1->DR & 0xFFFFUL);
}


/* -------------------------------------------------------------
 * Promedio móvil para estabilizar la lectura del ADC
 * ------------------------------------------------------------- */
static uint32_t ADC1_ReadMovingAverage(void)
{
    static uint32_t buffer[ADC_FILTER_SIZE] = {0U};
    static uint32_t index = 0U;
    static uint32_t sum = 0U;
    static uint32_t count = 0U;

    uint32_t new_sample;
    uint32_t average;

    new_sample = ADC1_ReadRaw();

    if (count < ADC_FILTER_SIZE)
    {
        buffer[index] = new_sample;
        sum += new_sample;
        count++;
    }
    else
    {
        sum -= buffer[index];
        buffer[index] = new_sample;
        sum += new_sample;
    }

    index++;

    if (index >= ADC_FILTER_SIZE)
    {
        index = 0U;
    }

    average = sum / count;

    return average;
}


/* -------------------------------------------------------------
 * PWM en PA5 / D13 / TIM2_CH1
 * -------------------------------------------------------------
 * PA5 está conectado a D13 y al LED LD2.
 * PA5 puede funcionar como TIM2_CH1 usando AF1.
 */
static void TIM2_CH1_PA5_PWM_Init_ByRegisters(void)
{
    RCC->AHB1ENR |= RCC_AHB1ENR_GPIOAEN;
    (void)RCC->AHB1ENR;

    /*
     * PA5 como función alternativa.
     */
    GPIOA->MODER &= ~(3UL << (5U * 2U));
    GPIOA->MODER |=  (2UL << (5U * 2U));

    GPIOA->OTYPER &= ~(1UL << 5U);

    GPIOA->OSPEEDR &= ~(3UL << (5U * 2U));
    GPIOA->OSPEEDR |=  (2UL << (5U * 2U));

    GPIOA->PUPDR &= ~(3UL << (5U * 2U));

    /*
     * AF1 en PA5 corresponde a TIM2_CH1.
     */
    GPIOA->AFR[0] &= ~(0xFUL << (5U * 4U));
    GPIOA->AFR[0] |=  (1UL   << (5U * 4U));

    RCC->APB1ENR |= RCC_APB1ENR_TIM2EN;
    (void)RCC->APB1ENR;

    TIM2->CR1 &= ~TIM_CR1_CEN;

    /*
     * f_TIM2 = 84 MHz
     * PSC = 83  -> f_CNT = 1 MHz
     * ARR = 999 -> f_PWM = 1 kHz
     */
    TIM2->PSC = 83U;
    TIM2->ARR = 999U;
    TIM2->CNT = 0U;

    TIM2->CCR1 = 0U;

    /*
     * Canal 1 como salida.
     */
    TIM2->CCMR1 &= ~TIM_CCMR1_CC1S;

    /*
     * PWM mode 1:
     * salida activa mientras CNT < CCR1.
     */
    TIM2->CCMR1 &= ~TIM_CCMR1_OC1M;
    TIM2->CCMR1 |=  (6UL << 4U);

    /*
     * Preload de CCR1.
     */
    TIM2->CCMR1 |= TIM_CCMR1_OC1PE;

    /*
     * Polaridad activa en alto y salida CH1 habilitada.
     */
    TIM2->CCER &= ~TIM_CCER_CC1P;
    TIM2->CCER |=  TIM_CCER_CC1E;

    /*
     * Preload de ARR.
     */
    TIM2->CR1 |= TIM_CR1_ARPE;

    /*
     * Conteo ascendente, edge-aligned.
     */
    TIM2->CR1 &= ~TIM_CR1_CMS;
    TIM2->CR1 &= ~TIM_CR1_DIR;

    /*
     * Cargar PSC, ARR y CCR.
     */
    TIM2->EGR |= TIM_EGR_UG;

    /*
     * Arrancar TIM2.
     */
    TIM2->CR1 |= TIM_CR1_CEN;
}


static void PWM_SetDutyFromADC(uint32_t adc_raw)
{
    uint32_t ccr_value;

    if (adc_raw > ADC_MAX_VALUE)
    {
        adc_raw = ADC_MAX_VALUE;
    }

    /*
     * ADC: 0 a 4095
     * PWM: 0 a 1000 cuentas
     */
    ccr_value = (adc_raw * PWM_PERIOD_COUNTS) / ADC_MAX_VALUE;

    TIM2->CCR1 = ccr_value;
}


/* -------------------------------------------------------------
 * Control de dirección para motor DC con L298N
 * -------------------------------------------------------------
 * ENA recibe la PWM desde PA5 / D13 / TIM2_CH1.
 *
 * IN1 -> PB5  / D4
 * IN2 -> PB10 / D6
 */
static void L298N_DirectionPins_Init_ByRegisters(void)
{
    RCC->AHB1ENR |= RCC_AHB1ENR_GPIOBEN;
    (void)RCC->AHB1ENR;

    /*
     * PB5 y PB10 como salidas digitales.
     */
    GPIOB->MODER &= ~((3UL << (L298N_IN1_PIN * 2U)) |
                      (3UL << (L298N_IN2_PIN * 2U)));

    GPIOB->MODER |=  ((1UL << (L298N_IN1_PIN * 2U)) |
                      (1UL << (L298N_IN2_PIN * 2U)));

    /*
     * Push-pull.
     */
    GPIOB->OTYPER &= ~((1UL << L298N_IN1_PIN) |
                       (1UL << L298N_IN2_PIN));

    /*
     * Velocidad baja.
     */
    GPIOB->OSPEEDR &= ~((3UL << (L298N_IN1_PIN * 2U)) |
                        (3UL << (L298N_IN2_PIN * 2U)));

    /*
     * Sin pull-up ni pull-down.
     */
    GPIOB->PUPDR &= ~((3UL << (L298N_IN1_PIN * 2U)) |
                      (3UL << (L298N_IN2_PIN * 2U)));

    L298N_MotorStop();
}


static void L298N_MotorForward(void)
{
    /*
     * IN1 = 1
     * IN2 = 0
     */
    GPIOB->BSRR = (1UL << L298N_IN1_PIN) |
                  (1UL << (L298N_IN2_PIN + 16U));

    motor_direction_text = "FORWARD";
}


static void L298N_MotorReverse(void)
{
    /*
     * IN1 = 0
     * IN2 = 1
     */
    GPIOB->BSRR = (1UL << (L298N_IN1_PIN + 16U)) |
                  (1UL << L298N_IN2_PIN);

    motor_direction_text = "REVERSE";
}


static void L298N_MotorStop(void)
{
    /*
     * IN1 = 0
     * IN2 = 0
     */
    GPIOB->BSRR = (1UL << (L298N_IN1_PIN + 16U)) |
                  (1UL << (L298N_IN2_PIN + 16U));

    motor_direction_text = "STOP";
}


/* -------------------------------------------------------------
 * Envío por USART2
 * ------------------------------------------------------------- */
static void USART2_SendADC_PWM_Values(uint32_t adc_value)
{
    char tx_buffer[160];

    uint32_t voltage_mv;
    uint32_t ccr_value;
    uint32_t duty_x10;
    int len;

    if (adc_value > ADC_MAX_VALUE)
    {
        adc_value = ADC_MAX_VALUE;
    }

    voltage_mv = (adc_value * 3300UL) / ADC_MAX_VALUE;

    ccr_value = (adc_value * PWM_PERIOD_COUNTS) / ADC_MAX_VALUE;

    duty_x10 = (ccr_value * 1000UL) / PWM_PERIOD_COUNTS;

    len = snprintf(tx_buffer,
                   sizeof(tx_buffer),
                   "ADC_filtrado=%4lu | V=%lu.%03lu V | CCR1=%4lu | Duty=%lu.%lu %% | Motor=%s\r\n",
                   (unsigned long)adc_value,
                   (unsigned long)(voltage_mv / 1000UL),
                   (unsigned long)(voltage_mv % 1000UL),
                   (unsigned long)ccr_value,
                   (unsigned long)(duty_x10 / 10UL),
                   (unsigned long)(duty_x10 % 10UL),
                   motor_direction_text);

    if (len > 0)
    {
        HAL_UART_Transmit(&huart2,
                          (uint8_t *)tx_buffer,
                          (uint16_t)len,
                          HAL_MAX_DELAY);
    }
}

/* -------------------------------------------------------------
 * Ahora las funciones del ultrasonido:
 *
 *HCSR04_DelayUs hace una demora en microsegundos
HAce una espera activa, que es indispensable porque el sensor
necesita un disparo originado por el microcontrolador en alto.
El while es la espera activa, que espera que la diferencia entre
el contador y el valor inicial sea igual al tiempo pedido
 *
 * ------------------------------------------------------------- */
static void HCSR04_DelayUs(uint32_t us)
{
    uint32_t start_count;

    /*
     * TIM1 está configurado con:
     *
     * f_TIM1 = 84 MHz
     * PSC = 83
     *
     * Por lo tanto:
     * f_CNT = 1 MHz
     * 1 cuenta = 1 us
     */
    start_count = __HAL_TIM_GET_COUNTER(&htim1);

    while ((__HAL_TIM_GET_COUNTER(&htim1) - start_count) < us)
    {
        /* Espera activa */
    }
}
/*HCSR04_Trigger(void); activa el trigger
Primero reinicia todas las variables para que no se pisen con mediciones anteriores.

1- Prepara para capturar el flanco de subida

2- Reinicia el contador desde cero, asi es mas facil obtener la referencia

3- Es importante limpiar los flag para no activar una interrupcion no necesaria

4- Genera el pulso del trigg, con la primer linea pone el cero el pin por 2ms,
Despues cambia la señal a 1 logico por 10ms
por ultimo lo deja nuevamente en cero.


     */

static void HCSR04_Trigger(void)
{
    /*
     * Reiniciar variables de medición.
     */
    hcsr04_capture_state = 0U;
    hcsr04_measurement_done = 0U;
    hcsr04_rising_edge = 0U;
    hcsr04_falling_edge = 0U;
    hcsr04_pulse_us = 0U;

    /*
     * Preparar TIM1_CH1 para capturar primero el flanco de subida.
     */
    __HAL_TIM_SET_CAPTUREPOLARITY(&htim1,
                                  TIM_CHANNEL_1,
                                  TIM_INPUTCHANNELPOLARITY_RISING);

    /*
     * Reiniciar contador antes de disparar el sensor.
     */
    __HAL_TIM_SET_COUNTER(&htim1, 0U);

    /*
     * Limpiar posible flag pendiente de captura.
     */
    __HAL_TIM_CLEAR_FLAG(&htim1, TIM_FLAG_CC1);

    /*
     * Generar pulso TRIG.
     *
     * El HC-SR04 requiere un pulso alto de al menos 10 us.
     */
    HAL_GPIO_WritePin(HCSR04_TRIG_PORT, HCSR04_TRIG_PIN, GPIO_PIN_RESET);
    HCSR04_DelayUs(2U);

    HAL_GPIO_WritePin(HCSR04_TRIG_PORT, HCSR04_TRIG_PIN, GPIO_PIN_SET);
    HCSR04_DelayUs(10U);

    HAL_GPIO_WritePin(HCSR04_TRIG_PORT, HCSR04_TRIG_PIN, GPIO_PIN_RESET);
}

/*Le da dos punteros, uno devuelve el ancho de pulso en ms
 * y el otro devuelve la distancia calculada, en el if
 * verifica si alguno de los dos es null para devolver un error.
 * En la siguiente linea lanza el trigger.
 * en la segunda linea hace una captura del tiempo que paso desde que inicio el programa

    */
static uint8_t HCSR04_ReadDistance_IC(uint32_t *pulse_us, uint32_t *distance_x10_cm)
{
    uint32_t start_tick;

    if ((pulse_us == NULL) || (distance_x10_cm == NULL))
    {
        return 0U;
    }

    /*
     * Disparar medición.
     */
    HCSR04_Trigger();

    start_tick = HAL_GetTick();

    /*
     * Esperar hasta que el Input Capture detecte:
     *
     * 1. Flanco de subida de ECHO.
     * 2. Flanco de bajada de ECHO.
     *
     * La medición termina cuando el callback coloca
     * hcsr04_measurement_done = 1.
     */
    while (hcsr04_measurement_done == 0U)
    {
        if ((HAL_GetTick() - start_tick) > HCSR04_TIMEOUT_MS)
        {
            /*
             * Si se cumple el plazo de esta funcion vuelve a cero
             * porque algo funciono mal, si se encuentra con un 1 se
             * ejecuta la proxima instrucciòn.
             * Modifica el ancho de pulso en
             * la memoria, despues toma ese pulso y calcula la distancia.

             */
            hcsr04_capture_state = 0U;

            __HAL_TIM_SET_CAPTUREPOLARITY(&htim1,
                                          TIM_CHANNEL_1,
                                          TIM_INPUTCHANNELPOLARITY_RISING);

            return 0U;
        }
    }

    *pulse_us = hcsr04_pulse_us;

    /*
     * Cálculo de distancia.
     *
     * Velocidad del sonido aproximada:
     * v = 343 m/s = 0,0343 cm/us
     *
     * El pulso ECHO representa ida y vuelta.
     *
     * distancia_cm = pulse_us * 0,0343 / 2
     * distancia_cm = pulse_us * 0,01715
     *
     * Para evitar float:
     *
     * distancia_x10_cm = distancia_cm * 10
     * distancia_x10_cm = pulse_us * 0,1715
     * distancia_x10_cm = pulse_us * 1715 / 10000
     *
     * Se suma 5000 para redondear.
     */
    *distance_x10_cm = (((*pulse_us) * 1715UL) + 5000UL) / 10000UL;

    return 1U;
}

/*
             *El HAL_TIM_IC_CaptureCallback no la llamamos nosotros, se aplica directamente cuando
             *configuramos la hal
   * Una vez que se almacena el valor del ccr1, ese valor se lleva al NVIC, que es el controlador
   * de las interrupciones si la interrupciòn esta habilitada, la cpu entra al HANDLER,
   * aca es diferente que hacerlo bare metal, porque dentro de ese handler la hal hace la siguiente
   * Funcion.
   * Cuando nosotros implementamos manualmente una interrupcion no usamos un callback, usamos
   * directamete el handler
             */
void HAL_TIM_IC_CaptureCallback(TIM_HandleTypeDef *htim)
{
    uint32_t captured_value;

    if (htim->Instance == TIM1)
    {
        if (htim->Channel == HAL_TIM_ACTIVE_CHANNEL_1)
        {
            /*
             * Leer el valor capturado en TIM1_CCR1,
             * ccr es el registro de captura o comparacion.
             */
            captured_value = HAL_TIM_ReadCapturedValue(htim, TIM_CHANNEL_1);

            /*
             * Estado 0:
             * se espera el flanco de subida de ECHO.
             */
            if (hcsr04_capture_state == 0U)
            {
                hcsr04_rising_edge = captured_value;
                hcsr04_capture_state = 1U;

                /*
                 * Una vez detectado el inicio del pulso,
                 * cambiamos la polaridad para capturar
                 * el flanco de bajada.
                 */
                __HAL_TIM_SET_CAPTUREPOLARITY(htim,
                                              TIM_CHANNEL_1,
                                              TIM_INPUTCHANNELPOLARITY_FALLING);
            }

            /*
             * Estado 1:
             * se espera el flanco de bajada de ECHO.
             */
            else if (hcsr04_capture_state == 1U)
            {
                hcsr04_falling_edge = captured_value;

                /*
                 * Calcular ancho del pulso ECHO.
                 *
                 * Caso normal:
                 * falling_edge >= rising_edge
                 *
                 * Caso con desborde:
                 * falling_edge < rising_edge
                 */
                if (hcsr04_falling_edge >= hcsr04_rising_edge)
                {
                    hcsr04_pulse_us = hcsr04_falling_edge - hcsr04_rising_edge;
                }
                else
                {
                    hcsr04_pulse_us = (TIM1_MAX_COUNT - hcsr04_rising_edge)
                                    + hcsr04_falling_edge
                                    + 1UL;
                }

                /*
                 * Marcar medición terminada.
                 */
                hcsr04_measurement_done = 1U;
                hcsr04_capture_state = 2U;

                /*
                 * Dejar el canal listo para la próxima medición:
                 * primero se capturará nuevamente flanco de subida.
                 */
                __HAL_TIM_SET_CAPTUREPOLARITY(htim,
                                              TIM_CHANNEL_1,
                                              TIM_INPUTCHANNELPOLARITY_RISING);
            }
        }
    }
}

/* En esta funcion envia los valores si son validos, el valor del pulso y distancia 0 */
static void USART2_SendDistance(uint8_t valid, uint32_t pulse_us, uint32_t distance_x10_cm)
{
    char tx_buffer[128];
    int len;

    if (valid != 0U)
    {
        len = snprintf(tx_buffer,
                       sizeof(tx_buffer),
                       "Echo=%5lu us | Distancia=%lu.%lu cm\r\n",
                       (unsigned long)pulse_us,
                       (unsigned long)(distance_x10_cm / 10UL),
                       (unsigned long)(distance_x10_cm % 10UL));
    }
    else
    {
        len = snprintf(tx_buffer,
                       sizeof(tx_buffer),
                       "Error: sin eco o fuera de rango\r\n");
    }

    if (len > 0)
    {
        HAL_UART_Transmit(&huart2,
                          (uint8_t *)tx_buffer,
                          (uint16_t)len,
                          HAL_MAX_DELAY);
    }
}
