int main(void)
{/* PRIMERO INICIALIZAO LA HAL, EL RELOJ EL GPIO Y EL USART 2 QUE COMPARTES AMBOS MODULOS*/
	HAL_Init();
	SystemClock_Config();
	MX_GPIO_Init();
	MX_USART2_UART_Init();
	MX_TIM1_Init();

    /*Main del ULTRASONIDO*/
	HAL_TIM_IC_Start_IT(&htim1, TIM_CHANNEL_1);/** Iniciar TIM1 Channel 1 en modo Input Capture con interrupción.* ECHO está conectado a D7 / PA8 / TIM1_CH1.
	   */
	HAL_GPIO_WritePin(HCSR04_TRIG_PORT, HCSR04_TRIG_PIN, GPIO_PIN_RESET);/*
	   * Asegurar TRIG en bajo al inicio.
	   * TRIG está conectado a D8 / PA9.
	   */

	/* MAIN DE MOTOR*/
	ADC1_PA4_Init_ByRegisters();
	TIM2_CH1_PA5_PWM_Init_ByRegisters();
	L298N_DirectionPins_Init_ByRegisters();

	  /*
	   * Sentido inicial del motor.
	   * La velocidad queda controlada por la PWM en ENA.
	   */
	  //L298N_MotorForward();
	L298N_MotorForward();


	while (1)
	{
	    uint32_t Ahora = HAL_GetTick();
	    /* ── aca defino un valor del tick a usar, que voya
	     * llamar Ahora como tiempo actual ── */

	    /* ── Tarea 1: ADC + PWM motor (cada 10 ms) ── */
	    static uint32_t last_motor_tick = 0U;
	    if ((Ahora - last_motor_tick) >= 10U)
	    {
	        last_motor_tick = Ahora;

	        uint32_t adc_filtered = ADC1_ReadMovingAverage();
	        PWM_SetDutyFromADC(adc_filtered);

	        /* ── Subtarea: UART motor (cada 1000ms  para que coincida con el sensor ) ── */
	        static uint32_t last_uart_motor_tick = 0U;
	        if ((Ahora - last_uart_motor_tick) >= 1000U)
	        {
	            last_uart_motor_tick = Ahora;
	            USART2_SendADC_PWM_Values(adc_filtered);
	        }
	    }

	    /* ── Tarea 2: HC-SR04 (cada 1000 ms) ── */
	    static uint32_t last_hcsr04_tick = 0U;
	    if ((Ahora - last_hcsr04_tick) >= HCSR04_MEASUREMENT_PERIOD_MS)
	    {
	        last_hcsr04_tick = Ahora;

	        uint32_t pulse_us = 0U;
	        uint32_t distance_x10_cm = 0U;
	        uint8_t valid = HCSR04_ReadDistance_IC(&pulse_us, &distance_x10_cm);

	        USART2_SendDistance(valid, pulse_us, distance_x10_cm);
	    }
	}
}











